from dataclasses import dataclass, field
from enum import Enum
from pathlib import Path

class IntegrationLocationType(str, Enum):
    SOURCE_CODE     = "source_code"      # .py, .ts, .js, etc.
    CONFIG_FILE     = "config_file"      # .yaml, .json, .env, .toml
    IAC_TEMPLATE    = "iac_template"     # Terraform, CDK, k8s manifests
    CI_PIPELINE     = "ci_pipeline"      # .github/workflows, Jenkinsfile

@dataclass
class IntegrationOccurrence:
    file_path: Path
    line_number: int
    location_type: IntegrationLocationType
    deprecated_model_id: str
    snippet: str              # the line containing the model ID

@dataclass
class DeprecationAuditReport:
    deprecated_model_id: str
    eol_date: str
    occurrences: list[IntegrationOccurrence] = field(default_factory=list)

    def by_type(self, loc_type: IntegrationLocationType) -> list[IntegrationOccurrence]:
        return [o for o in self.occurrences if o.location_type == loc_type]

    def total_locations(self) -> int:
        return len(self.occurrences)

    def migration_complete(self) -> bool:
        return len(self.occurrences) == 0

    def summary(self) -> str:
        lines = [f"Deprecation audit: {self.deprecated_model_id} (EOL: {self.eol_date})"]
        lines.append(f"  Total occurrences: {self.total_locations()}")
        for loc_type in IntegrationLocationType:
            count = len(self.by_type(loc_type))
            if count > 0:
                lines.append(f"    {loc_type.value}: {count}")
        return "\n".join(lines)

from dataclasses import dataclass, field
from datetime import date, timedelta
from enum import Enum

class MigrationStatus(str, Enum):
    NOT_STARTED     = "not_started"
    IN_PROGRESS     = "in_progress"
    MIGRATED        = "migrated"    # code changed, not yet in production
    VERIFIED        = "verified"    # confirmed in production on replacement model

@dataclass
class IntegrationMigrationState:
    service_name: str
    deprecated_model_id: str
    replacement_model_id: str
    risk_tier: str            # "low" | "medium" | "high"
    status: MigrationStatus
    owner: str
    deadline: date
    notes: str = ""

    def days_remaining(self, today: date) -> int:
        return (self.deadline - today).days

    def is_at_risk(self, today: date) -> bool:
        days = self.days_remaining(today)
        if self.risk_tier == "high" and days < 14:
            return True
        if self.risk_tier == "medium" and days < 7:
            return True
        return days < 3

    def status_label(self, today: date) -> str:
        if self.status == MigrationStatus.VERIFIED:
            return "DONE"
        days = self.days_remaining(today)
        if days < 0:
            return "OVERDUE"
        if self.is_at_risk(today):
            return f"AT_RISK ({days}d)"
        return f"PENDING ({days}d)"

@dataclass
class SunsetProgressDashboard:
    migrations: list[IntegrationMigrationState] = field(default_factory=list)

    def by_status(self, status: MigrationStatus) -> list[IntegrationMigrationState]:
        return [m for m in self.migrations if m.status == status]

    def at_risk(self, today: date) -> list[IntegrationMigrationState]:
        return [m for m in self.migrations
                if m.status != MigrationStatus.VERIFIED and m.is_at_risk(today)]

    def completion_rate(self) -> float:
        if not self.migrations:
            return 1.0
        verified = len(self.by_status(MigrationStatus.VERIFIED))
        return verified / len(self.migrations)

    def unverified_by_risk(self, today: date) -> dict[str, int]:
        unverified = [m for m in self.migrations if m.status != MigrationStatus.VERIFIED]
        return {
            "high": sum(1 for m in unverified if m.risk_tier == "high"),
            "medium": sum(1 for m in unverified if m.risk_tier == "medium"),
            "low": sum(1 for m in unverified if m.risk_tier == "low"),
        }

from dataclasses import dataclass
from datetime import datetime

@dataclass
class EOLIncidentRecord:
    service_name: str
    deprecated_model_id: str
    first_error_at: datetime
    calls_failed: int
    root_cause: str     # "stale_image" | "missed_config" | "cache" | "inflight"
    resolved_at: datetime | None = None
    resolution: str = ""

    def mttr_minutes(self) -> float | None:
        if self.resolved_at is None:
            return None
        return (self.resolved_at - self.first_error_at).total_seconds() / 60

    def is_resolved(self) -> bool:
        return self.resolved_at is not None

KNOWN_ROOT_CAUSES = {
    "stale_image": (
        "A container image built before the migration is still running. "
        "Trigger a fresh deployment from the post-migration commit."
    ),
    "missed_config": (
        "A config file or environment variable was not updated during migration. "
        "Locate the config, update the model ID, and redeploy."
    ),
    "cache": (
        "A CDN or application cache contains a response generated by the "
        "deprecated model. Flush the cache and verify new requests route correctly."
    ),
    "inflight": (
        "Requests submitted before EOL are still being processed. "
        "Monitor error rate; should resolve without intervention as in-flight "
        "requests complete."
    ),
}

def eol_triage(error_response: dict) -> str:
    model_id = error_response.get("error", {}).get("model_id", "")
    return (
        f"EOL call detected for {model_id!r}. "
        f"Check for: stale container images, missed config files, "
        f"routing caches. Escalate to service owner immediately."
    )
